  ('jee-mathematics-binomial-theorem-q03', 'jee-mathematics-binomial-theorem', 'The coefficient of x² in the expansion of (1 + x) raised to 4 is:', '12', '4', '8', '6', 'D', 'The coefficient is 4C2 = 6.', 2),
