  ('jee-mathematics-matrices-determinants-q08', 'jee-mathematics-matrices-determinants', 'The diagonal elements of a skew-symmetric matrix are all:', 'Zero', 'One', 'Equal', 'Negative', 'A', 'A skew-symmetric matrix has all diagonal entries zero.', 7),
  ('jee-mathematics-straight-lines-circles-q01', 'jee-mathematics-straight-lines-circles', 'The slope of the line passing through (1, 2) and (3, 6) is:', '1', '2', '3', '4', 'B', 'Slope = (6 - 2)/(3 - 1) = 4/2 = 2.', 0),
  ('jee-mathematics-straight-lines-circles-q02', 'jee-mathematics-straight-lines-circles', 'Two lines are perpendicular when the product of their slopes is:', '0', '1', '-1', 'Infinite', 'C', 'Perpendicular lines satisfy m1 times m2 = -1.', 1),
  ('jee-mathematics-straight-lines-circles-q03', 'jee-mathematics-straight-lines-circles', 'The radius of the circle x² + y² = 49 is:', '7', '49', '14', '24.5', 'A', 'Comparing with x² + y² = r² gives r = sqrt(49) = 7.', 2),
