  ('jee-chemistry-metallurgy-q07', 'jee-chemistry-metallurgy', 'The Mond process refines which metal via a volatile carbonyl?', 'Iron', 'Lead', 'Zinc', 'Nickel', 'D', 'The Mond process purifies nickel through its volatile carbonyl compound.', 6),
  ('jee-chemistry-metallurgy-q08', 'jee-chemistry-metallurgy', 'The unwanted earthy impurity present in an ore is called:', 'Gangue', 'Slag', 'Flux', 'Matte', 'A', 'The unwanted rocky impurity in an ore is called the gangue.', 7),
  ('jee-chemistry-environmental-chemistry-q01', 'jee-chemistry-environmental-chemistry', 'Which gas binds strongly to haemoglobin, reducing oxygen transport?', 'Carbon dioxide', 'Nitrogen', 'Carbon monoxide', 'Oxygen', 'C', 'Carbon monoxide binds haemoglobin far more strongly than oxygen, causing poisoning.', 0),
  ('jee-chemistry-environmental-chemistry-q02', 'jee-chemistry-environmental-chemistry', 'Acid rain is caused mainly by oxides of sulphur and:', 'Carbon', 'Sodium', 'Helium', 'Nitrogen', 'D', 'Sulphur and nitrogen oxides form sulphuric and nitric acids, causing acid rain.', 1),
  ('jee-chemistry-environmental-chemistry-q03', 'jee-chemistry-environmental-chemistry', 'The ozone layer is depleted mainly by:', 'Carbon dioxide', 'Chlorofluorocarbons', 'Methane', 'Water vapour', 'B', 'CFCs release chlorine atoms that catalytically destroy stratospheric ozone.', 2),
