  ('jee-chemistry-environmental-chemistry-q08', 'jee-chemistry-environmental-chemistry', 'Low dissolved oxygen (DO) in a river is harmful because it:', 'Suffocates aquatic life', 'Helps aquatic life', 'Raises water clarity', 'Has no effect', 'A', 'Low dissolved oxygen suffocates fish and other aquatic organisms.', 7),
  ('jee-mathematics-sets-relations-functions-q01', 'jee-mathematics-sets-relations-functions', 'The number of subsets of a set with n elements is:', 'n squared', 'Two times n', 'n factorial', 'Two to the power n', 'D', 'A set with n elements has two to the power n subsets.', 0),
  ('jee-mathematics-sets-relations-functions-q02', 'jee-mathematics-sets-relations-functions', 'A function that is both one-one and onto is called:', 'Bijective', 'Surjective only', 'Injective only', 'Constant', 'A', 'A function that is both one-one and onto is bijective.', 1),
  ('jee-mathematics-sets-relations-functions-q03', 'jee-mathematics-sets-relations-functions', 'An equivalence relation must be reflexive, symmetric and:', 'Irreflexive', 'Antisymmetric', 'Transitive', 'Empty', 'C', 'An equivalence relation is reflexive, symmetric and transitive.', 2),
