  ('jee-mathematics-sets-relations-functions-q05', 'jee-mathematics-sets-relations-functions', 'For two sets, n(A union B) equals n(A) plus n(B) minus:', 'n(A intersection B)', 'n(A) times n(B)', 'Zero', 'n(A) minus n(B)', 'A', 'By the inclusion-exclusion principle, subtract the intersection count.', 4),
  ('jee-mathematics-sets-relations-functions-q06', 'jee-mathematics-sets-relations-functions', 'Composition of functions is generally:', 'Commutative', 'Always the identity', 'Not commutative', 'Undefined', 'C', 'In general f composed with g differs from g composed with f.', 5),
  ('jee-mathematics-sets-relations-functions-q07', 'jee-mathematics-sets-relations-functions', 'Which type of function has an inverse?', 'Bijective', 'Only onto', 'Only one-one', 'Constant', 'A', 'Only a bijective function has a well-defined inverse.', 6),
