  ('jee-mathematics-trigonometric-identities-q07', 'jee-mathematics-trigonometric-identities', 'The value of tan 45 degrees is:', 'One', 'Zero', 'Root three', 'One over root three', 'A', 'The tangent of 45 degrees equals one.', 6),
