  ('jee-mathematics-inverse-trigonometry-q04', 'jee-mathematics-inverse-trigonometry', 'The derivative of arctan x is:', 'One over the square root of (1 minus x squared)', 'One over (1 minus x squared)', 'Minus one over (1 plus x squared)', 'One over (1 plus x squared)', 'D', 'The derivative of arctan x is one over (1 plus x squared).', 3),
  ('jee-mathematics-inverse-trigonometry-q05', 'jee-mathematics-inverse-trigonometry', 'The value of arctan x plus arccot x is:', 'Zero', 'pi', 'pi over two', 'pi over four', 'C', 'For all real x, arctan x plus arccot x equals pi over two.', 4),
