  ('ssc-cgl-general-awareness-books-authors-awards-q05', 'ssc-cgl-general-awareness-books-authors-awards', 'Who won the Nobel Prize in Literature in 1913 for Gitanjali?', 'Amartya Sen', 'Rabindranath Tagore', 'Khushwant Singh', 'Jawaharlal Nehru', 'B', 'Rabindranath Tagore won the Nobel Prize in Literature in 1913 for Gitanjali.', 4),
